const b = $input.first().json.body || $input.first().json;
if (!b.client_id || !b.video_brief) throw new Error('client_id and video_brief required');
if (!b.target_platforms || b.target_platforms.length === 0) {
  b.target_platforms = ['instagram_reels', 'tiktok', 'youtube_shorts'];
}
return [{ json: {
  task_id: `video_${Date.now()}_${Math.random().toString(36).slice(2,8)}`,
  client_id: b.client_id,
  video_brief: b.video_brief,
  style: b.style || 'dynamic',
  target_platforms: b.target_platforms,
  duration_s: b.duration_s || 15,
  aspect_ratio: b.aspect_ratio || '9:16',
  reference_image: b.reference_image || null,
  brand_assets_url: b.brand_assets_url || null,
  started_at: new Date().toISOString()
} }];

// Rebuild per-platform export specs, pulling state back from Validate Brief
const vb = $('Code: Validate Brief').item.json;
const whisper = $('OpenAI Whisper: Auto-Subtitle').item.json || {};
const platforms = vb.target_platforms || ['instagram_reels'];
const specs = {
  tiktok: { aspect: '9:16', res: '1080x1920', bitrate: '4M', fps: 30 },
  instagram_reels: { aspect: '9:16', res: '1080x1920', bitrate: '5M', fps: 30 },
  youtube_shorts: { aspect: '9:16', res: '1080x1920', bitrate: '5M', fps: 30 },
  youtube: { aspect: '16:9', res: '1920x1080', bitrate: '8M', fps: 30 }
};
const exportsCfg = platforms.map(p => {
  const s = specs[p] || specs.instagram_reels;
  return {
    platform: p,
    aspect_ratio: s.aspect,
    resolution: s.res,
    bitrate: s.bitrate,
    fps: s.fps,
    ffmpeg_cmd: `ffmpeg -i input.mp4 -vf scale=${s.res} -b:v ${s.bitrate} -r ${s.fps} output_${p}.mp4`,
    subtitles: whisper.content || ''
  };
});
return [{ json: {
  ...vb,
  exports_config: exportsCfg,
  subtitle_vtt: whisper.content || ''
} }];

